params.text:
# LangGraph ST Agent Configuration
# ================================

# RP LLM (Creative roleplay model)
RP_LLM_BASE_URL={{input.rp_url || 'http://localhost:5001'}}
RP_LLM_API_KEY=none
RP_LLM_MODEL={{input.rp_model || ''}}
RP_LLM_BACKEND={{input.rp_backend || 'kobold'}}

# Logic LLM (State extraction model)
LOGIC_LLM_BASE_URL={{input.logic_url || 'http://localhost:11434'}}
LOGIC_LLM_API_KEY=none
LOGIC_LLM_MODEL={{input.logic_model || 'llama3'}}
LOGIC_LLM_BACKEND={{input.logic_backend || 'ollama'}}

# Server
SERVER_PORT=8001

# Agent
CONTEXT_WINDOW_MESSAGES=20
DB_RETRIEVAL_COUNT=10
DEBUG_MODE=false
